-- 6. Maidstone Borough × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'maidstone-borough',
  'Maidstone Borough''s social media landscape reflects the county town''s scale and diversity. Facebook community groups cover the town centre, Bearsted, Loose, Headcorn, Staplehurst, Lenham, and every significant parish in the borough. Instagram drives engagement for the restaurants and independents around Fremlin Walk and the High Street. LinkedIn connects the professional community at Eclipse Park and 20-20. With 175,000 residents across these overlapping online communities, the opportunity for social media visibility is the largest in Kent. Yet the majority of Maidstone businesses either have no social presence, maintain dormant profiles, or present inconsistent branding across platforms. In a market this competitive, a properly set up social media presence is not optional. It is the baseline requirement for being found, recommended, and chosen. We build and optimise your social media profiles so your Maidstone business is ready to convert attention from the county town''s active online communities.',
  'Maidstone''s social media landscape is the most active in Kent due to the borough''s population and commercial diversity. Multiple Facebook community groups serve different areas, with the main Maidstone groups having tens of thousands of members. Village-specific groups for Bearsted, Headcorn, and Staplehurst drive hyperlocal recommendations. Instagram has a strong following among the town centre''s food and drink scene. LinkedIn is significant for the professional services and corporate community concentrated around Eclipse Park and the County Hall area. Google reviews carry enormous weight in a market where customers have abundant choice.',
  'Social media maturity in Maidstone is slightly higher than most Kent towns due to the competitive pressure, but significant gaps remain. Some hospitality and retail businesses near Fremlin Walk maintain active Instagram accounts. Eclipse Park firms generally have LinkedIn pages. However, trades businesses, professional services, and village-based businesses across the borough are predominantly absent or dormant on social media. The businesses that maintain consistent, well-branded profiles report strong returns from community group referrals.',
  'We set up social media for Maidstone Borough businesses based on where your specific audience engages. Trades targeting homeowners across the borough get Facebook profiles optimised for every community group from Maidstone town to Lenham. Eclipse Park professional services get LinkedIn company pages built for B2B credibility. Town-centre hospitality gets Instagram-first strategies. Every profile is branded consistently and optimised for local discovery across the full borough.',
  '{"population": 175000, "growth": "Kent''s most active social media community landscape", "business_districts": ["Town Centre", "Fremlin Walk", "Eclipse Park", "Bearsted", "Headcorn", "Staplehurst"], "key_fact": "Multiple overlapping community groups create the largest social media opportunity in Kent"}',
  '[{"title": "Missing from the county town''s most active recommendation networks", "description": "When a Bearsted resident asks for a plumber, or a Maidstone town group member requests a restaurant recommendation, businesses without social profiles are invisible. These groups generate genuine, high-intent referrals daily across the borough''s multiple communities, and without profiles your business cannot participate."}, {"title": "Dormant profiles failing in a market where activity signals reliability", "description": "In Maidstone''s competitive market, customers check social media to verify businesses are active, legitimate, and responsive. A dormant Facebook page or an empty Instagram profile sends a signal that your business is not engaged. In a borough with 175,000 potential customers, that signal costs you daily."}, {"title": "No LinkedIn presence for the county town''s professional market", "description": "Eclipse Park and the County Hall area concentrate Kent''s largest professional services community. Decision-makers here research suppliers on LinkedIn before making contact. Without a polished company page, your business is invisible to this high-value B2B audience."}]',
  '[{"title": "Borough-wide Facebook setup for Kent''s largest community network", "description": "We build and optimise your Facebook business profile for engagement across every community group in Maidstone Borough. From the main Maidstone groups to parish-specific pages in Bearsted, Headcorn, and Staplehurst, your profile is ready to convert recommendations into enquiries across the county town''s active social landscape."}, {"title": "Platform-specific setup for your Maidstone audience", "description": "Trades get Facebook-first setups for community group engagement. Restaurants and retailers near Fremlin Walk get Instagram profiles with professional content templates. Eclipse Park firms get LinkedIn company pages built for B2B authority. Every platform is chosen and configured for your specific audience within the borough."}, {"title": "Consistent cross-platform brand presence across Kent''s county town", "description": "Same logo, colours, contact details, and messaging across every platform. In a market where customers cross-reference businesses on multiple channels before making contact, consistent presentation builds the trust and recognition that converts browsing into buying."}]',
  '[{"question": "Which social platforms matter most in Maidstone?", "answer": "For trades and home services, Facebook is essential due to the borough''s numerous active community groups. For hospitality and retail near the town centre, Instagram drives footfall. For professional services at Eclipse Park, LinkedIn is critical. We recommend the platforms that match your specific audience."}, {"question": "Do you manage ongoing social media or just set it up?", "answer": "This service covers professional setup and optimisation. We create, brand, and configure your profiles for the Maidstone market and provide content templates and posting guides. Ongoing management is available as a separate service for businesses wanting a fully hands-off approach."}, {"question": "How important are Google reviews for Maidstone businesses?", "answer": "Exceptionally important. In a competitive market with 175,000 residents comparing options, reviews are often the deciding factor. We set up your Google Business Profile with optimised categories and a structured review generation strategy that makes it easy for satisfied customers to share their experience."}, {"question": "Can you set up profiles that cover both the town centre and villages?", "answer": "Yes. We ensure your profiles indicate service coverage across the full borough, from the town centre to Bearsted, Headcorn, Staplehurst, and Lenham. This breadth ensures your business appears in social searches and recommendations from every community in the county town."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
