  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs,
  layout_variant = EXCLUDED.layout_variant;

-- 7. Maidstone Borough × Digital Marketing
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'digital-marketing',
  'maidstone-borough',
  'Maidstone Borough''s 175,000 residents represent Kent''s largest single-borough marketing opportunity. As the county town with the highest concentration of businesses, professional services, and retail activity in the region, the potential customer base is enormous. But so is the competition. In a market where multiple businesses compete for every customer, the ones that invest in targeted digital marketing capture disproportionate market share. Businesses that rely solely on word of mouth or passive visibility lose ground daily to competitors who run precise campaigns reaching the right audience at the right moment. Our digital marketing campaigns are built specifically for the scale and competition of Maidstone Borough, using paid search, social advertising, and hyper-local targeting to connect your business with customers across the county town''s full catchment.',
  'Maidstone Borough''s digital marketing landscape reflects the county town''s commercial significance. Google Ads competition for Maidstone keywords is the highest in Kent. Facebook reaches the borough''s active community groups. LinkedIn targets the Eclipse Park and professional services audience. The surrounding villages create long-tail advertising opportunities with less competition. Leeds Castle tourism drives seasonal hospitality marketing. The M20 corridor brings through-traffic that can be captured with location-based ads. Commuter rail services create mobile advertising windows during peak travel times.',
  'Digital advertising competition in Maidstone is intense. Google Ads costs for core service keywords are among the highest in Kent. National and regional firms advertising into the county town drive up costs further. However, village-level targeting around Bearsted, Headcorn, and Staplehurst faces significantly less competition. Social media advertising remains underutilised by most local businesses, creating opportunity. The businesses that advertise intelligently rather than broadly achieve strong returns.',
  'We build Maidstone Borough campaigns around precision rather than volume. Town-centre campaigns target specific postcodes with messaging tailored to the urban audience. Village campaigns reach homeowners in Bearsted, Headcorn, Staplehurst, and Lenham with area-specific messaging. Eclipse Park campaigns target B2B decision-makers by industry and role. Every campaign is measured against leads and revenue generated, with continuous optimisation to maximise return in Kent''s most competitive advertising market.',
  '{"population": 175000, "growth": "Kent''s largest marketing opportunity with corresponding competition", "business_districts": ["Town Centre", "Eclipse Park", "20-20 Business Park", "Bearsted", "Headcorn", "Staplehurst"], "key_fact": "Highest Google Ads competition in Kent — precision targeting essential for ROI"}',
  '[{"title": "Competitors outspending you in Kent''s most contested ad market", "description": "Maidstone''s Google Ads landscape is the most expensive in Kent. Businesses running broad, unoptimised campaigns burn through budget while competitors with precision-targeted campaigns capture the highest-value leads. Without expert management, advertising in the county town becomes an expensive exercise in waste."}, {"title": "Village audiences overlooked while town-centre campaigns drain budget", "description": "Many Maidstone businesses concentrate their advertising on the town centre while ignoring the substantial populations of Bearsted, Headcorn, Staplehurst, Lenham, and other parishes. These village audiences face less advertising competition and often generate higher-value leads at lower cost per acquisition."}, {"title": "No measurement of which marketing drives actual Maidstone revenue", "description": "In a market as competitive as Maidstone, every marketing pound must be accounted for. Yet most borough businesses cannot identify which campaigns, keywords, or platforms generate their paying customers. Without tracking, optimisation is impossible, and budget is wasted on activity that feels productive but delivers nothing."}]',
  '[{"title": "Precision-targeted campaigns for Kent''s busiest market", "description": "We build campaigns targeting specific postcodes, demographics, and audience segments within Maidstone Borough. Town-centre, village, and business park audiences each receive tailored messaging. This precision ensures maximum impact in a market where broad, untargeted campaigns waste budget against intense competition."}, {"title": "Village-level campaigns capturing the borough''s wider catchment", "description": "We create separate campaign segments for Bearsted, Headcorn, Staplehurst, Lenham, and other parishes. These lower-competition areas generate high-quality leads at a fraction of the cost of town-centre advertising. Combined, the village audience represents a substantial portion of the borough''s 175,000 residents."}, {"title": "Full conversion tracking in Kent''s most competitive market", "description": "Every campaign includes complete tracking from ad click to paying customer. In Maidstone''s expensive advertising market, knowing exactly which keywords, ads, and audiences generate revenue is not optional. Monthly reporting shows your cost per lead and return on investment in clear terms."}]',
  '[{"question": "What budget do Maidstone Borough businesses need for effective advertising?", "answer": "Maidstone has the highest advertising costs in Kent. Most service businesses need seven hundred to two thousand pounds monthly in ad spend for meaningful results. Village-targeting campaigns can achieve strong results with lower budgets. We provide forecasts based on actual Maidstone keyword costs before you commit."}, {"question": "Is it worth advertising in Maidstone given the high competition?", "answer": "The competition reflects the opportunity. With 175,000 residents and Kent''s highest commercial density, the return per customer often justifies higher acquisition costs. The key is precision: targeting the right audience in the right area with the right message, rather than competing broadly against all advertisers."}, {"question": "Can you target specific villages within the borough?", "answer": "Yes. We create separate campaigns for Bearsted, Headcorn, Staplehurst, Lenham, and other parishes. This village-level targeting captures audiences that most competitors ignore, often generating leads at significantly lower cost than town-centre campaigns."}, {"question": "How quickly will I see results from digital marketing in Maidstone?", "answer": "Paid search generates enquiries from the first week. Social media campaigns build momentum over two to four weeks. We provide weekly reporting from launch, and continuous optimisation ensures improving performance over time."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
